generated_oml:
// Sensing components
instance HokuyoUST10LX_SensingComponent : DTDFVocab:SensingComponent [
    base:desc "Hokuyo UST 10LX LiDAR providing high‑resolution 3‑D point clouds"
    DTDFVocab:producedData LiDARPointCloudTransmitted
]
instance RealSenseD435i_SensingComponent : DTDFVocab:SensingComponent [
    base:desc "Intel RealSense D435i depth camera delivering RGB‑D streams"
    DTDFVocab:producedData DepthImageTransmitted
]
instance VehicleSpeedSensor_SensingComponent : DTDFVocab:SensingComponent [
    base:desc "Vehicle‑attached speed sensor reporting wheel encoder velocities"
    DTDFVocab:producedData SpeedDataTransmitted
]
instance SteeringAngleSensor_SensingComponent : DTDFVocab:SensingComponent [
    base:desc "Steering angle sensor measuring steering encoder positions"
    DTDFVocab:producedData SteeringAngleDataTransmitted
]

// Physical-to-virtual interaction
instance LiDARPointCloudTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom HokuyoUST10LX_SensingComponent
]
instance DepthImageTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom RealSenseD435i_SensingComponent
]
instance SpeedDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom VehicleSpeedSensor_SensingComponent
]
instance SteeringAngleDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom SteeringAngleSensor_SensingComponent
]

// Data
instance LiDARPointCloudData : DTDFVocab:Data [
    base:desc "Timestamped point‑cloud data stream from Hokuyo UST 10LX LiDAR"
    DTDFVocab:fromData LiDARPointCloudTransmitted
    DTDFVocab:inputTo DataPreProcessingEnabler, RealTimeMonitoringEnabler, DataStorageEnabler
]
instance DepthImageData : DTDFVocab:Data [
    base:desc "Timestamped RGB‑D image stream from Intel RealSense D435i camera"
    DTDFVocab:fromData DepthImageTransmitted
    DTDFVocab:inputTo DataPreProcessingEnabler, RealTimeMonitoringEnabler, DataStorageEnabler
]
instance SpeedData : DTDFVocab:Data [
    base:desc "Timestamped vehicle speed information from wheel encoder"
    DTDFVocab:fromData SpeedDataTransmitted
    DTDFVocab:inputTo DataPreProcessingEnabler, ACCControlEnabler, RealTimeMonitoringEnabler, DataStorageEnabler
]
instance SteeringAngleData : DTDFVocab:Data [
    base:desc "Timestamped steering angle measurement from steering encoder"
    DTDFVocab:fromData SteeringAngleDataTransmitted
    DTDFVocab:inputTo DataPreProcessingEnabler, ACCControlEnabler, RealTimeMonitoringEnabler, DataStorageEnabler
]

// Services
instance RealTimeMonitoringService : DTDFVocab:Service [
    base:desc "Service that monitors telemetry, generates CSV reports, and stores data in the SQL database"
    DTDFVocab:provides DiagnosticReportInsight, GenerateTimeSeriesReportAction
]
instance ACCComputationOffloadService : DTDFVocab:Service [
    base:desc "Service that offloads ACC algorithm computation to the cloud and issues desired speed commands"
    DTDFVocab:provides AdjustDesiredSpeedAction, IssueEmergencyBrakeAction
]
instance RemoteManagementService : DTDFVocab:Service [
    base:desc "Service that allows operators to enable/disable ACC, modify desired speed, and trigger emergency braking"
    DTDFVocab:provides EnableACCAction, DisableACCAction, AdjustDesiredSpeedAction
]
instance DataStorageService : DTDFVocab:Service [
    base:desc "Service that stores time‑stamped vehicle state and track data into an external SQL database"
    DTDFVocab:provides DataStorageInsight
]
instance VisualizationService : DTDFVocab:Service [
    base:desc "Service that renders 3‑D scene visualization of vehicle environment and projected path"
    DTDFVocab:provides SceneVisualizationInsight
]
instance DataPreProcessingService : DTDFVocab:Service [
    base:desc "Service that processes raw sensor data using DBSCAN and Kalman filters to produce object tracks"
    DTDFVocab:provides ObjectTrackInsight
]

// Insights
instance DiagnosticReportInsight : DTDFVocab:Insight [
    base:desc "Diagnostic report summarizing vehicle performance and safety‑critical events"
]
instance ObjectTrackInsight : DTDFVocab:Insight [
    base:desc "Insight on processed object tracks generated by DBSCAN and Kalman filter"
]
instance SceneVisualizationInsight : DTDFVocab:Insight [
    base:desc "Real‑time 3‑D visualization of the vehicle's environment and projected path"
]
instance DataStorageInsight : DTDFVocab:Insight [
    base:desc "Statistical insight about data stored in the external SQL database"
]

// Actions
instance GenerateTimeSeriesReportAction : DTDFVocab:Action [
    base:desc "Action to generate time‑series CSV reports of object tracks and vehicle state"
    DTDFVocab:IsAutomatic true
]
instance AdjustDesiredSpeedAction : DTDFVocab:Action [
    base:desc "Action to adjust the desired speed input to the ACC algorithm"
    DTDFVocab:IsAutomatic false
]
instance IssueEmergencyBrakeAction : DTDFVocab:Action [
    base:desc "Action to trigger emergency braking of the vehicle"
    DTDFVocab:IsAutomatic false
]
instance EnableACCAction : DTDFVocab:Action [
    base:desc "Action to enable Adaptive Cruise Control"
    DTDFVocab:IsAutomatic false
]
instance DisableACCAction : DTDFVocab:Action [
    base:desc "Action to disable Adaptive Cruise Control"
    DTDFVocab:IsAutomatic false
]

// Enablers
instance DataPreProcessingEnabler : DTDFVocab:Enabler [
    base:desc "ROS2 node that performs DBSCAN clustering and Kalman filter tracking on raw sensor data"
    DTDFVocab:enables DataPreProcessingService
]
instance ACCControlEnabler : DTDFVocab:Enabler [
    base:desc "ROS2 node responsible for Adaptive Cruise Control (ACC) computations and command generation"
    DTDFVocab:enables ACCComputationOffloadService
]
instance VisualizationEnabler : DTDFVocab:Enabler [
    base:desc "ROS2 node that renders 3‑D scene and projected vehicle path"
    DTDFVocab:enables VisualizationService
]
instance RemoteManagementEnabler : DTDFVocab:Enabler [
    base:desc "ROS2 node that handles remote operator commands for ACC enable/disable and speed tuning"
    DTDFVocab:enables RemoteManagementService
]
instance DataStorageEnabler : DTDFVocab:Enabler [
    base:desc "ROS2 node that stores time‑stamped state and track data into an external SQL database"
    DTDFVocab:enables DataStorageService
]
instance RealTimeMonitoringEnabler : DTDFVocab:Enabler [
    base:desc "ROS2 node that aggregates live telemetry and generates diagnostic CSV reports"
    DTDFVocab:enables RealTimeMonitoringService
]

// Models
instance DBSCANModel : DTDFVocab:Model [
    base:desc "DBSCAN‑based clustering model applied to LiDAR point clouds for obstacle identification"
    DTDFVocab:inputTo DataPreProcessingEnabler
]
instance KalmanFilterModel : DTDFVocab:Model [
    base:desc "Kalman filter model used for tracking object positions across frames"
    DTDFVocab:inputTo DataPreProcessingEnabler
]
instance ACCControlModel : DTDFVocab:Model [
    base:desc "ACC control model compliant with ISO 15622 for desired speed calculation"
    DTDFVocab:inputTo ACCControlEnabler
]
instance SceneRenderingModel : DTDFVocab:Model [
    base:desc "3‑D visualization model that projects vehicle state and predicted path"
    DTDFVocab:inputTo VisualizationEnabler
]

// Environment containing components
instance VehicleTwinEnvironment : DTDFVocab:Environment [
    base:contains HokuyoUST10LXComponent, RealSenseD435iComponent, VehicleSpeedSensorComponent, SteeringAngleSensorComponent, VehicleActuationComponent
]

// Component instances for sensors and actuator
instance HokuyoUST10LXComponent : DTDFVocab:Component [
    base:desc "Hokuyo UST 10LX LiDAR sensor component"
]
instance RealSenseD435iComponent : DTDFVocab:Component [
    base:desc "Intel RealSense D435i depth camera component"
]
instance VehicleSpeedSensorComponent : DTDFVocab:Component [
    base:desc "Vehicle speed sensor component"
]
instance SteeringAngleSensorComponent : DTDFVocab:Component [
    base:desc "Steering angle sensor component"
]
instance VehicleActuationComponent : DTDFVocab:Component [
    base:desc "Vehicle actuation component controlling motor and steering servos"
]

instance virtual_to_physical_interaction : DTDFVocab:VirtualToPhysical [
    base:desc "The Digital Twin Entity’s ACC‑controlling Functional Entity computes a desired speed from the lead vehicle distance and forwards command messages via the Data Translation Functional Entity to the Data Collection Functional Entity on the vehicle, where the Actuation FE converts the desired speed into motor voltage commands and steering commands, effectively actuating the physical vehicle."
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "All DT services run at real‑time rates compatible with the vehicle’s perception cycle (≈ 10 Hz). End‑to‑end communication latency is bounded at 100 ms, and all participating nodes maintain clock synchronization accuracy within 100 ms, satisfying the network performance constraints required for real‑time ACC operation."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "The constellation follows ISO 23247’s entity‑based architecture: observable manufacturing elements (OEME) are mapped to a Physical Twin Entity (mounted on the vehicle), while the Digital Twin Entity processes data and performs ACC computation. The User Entity hosts a 3‑D visualization and a control panel, and a Cross‑System Entity provides data translation. Each entity comprises multiple Functional Entities packaged as ROS 2 packages and deployed across vehicle and cloud nodes."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "The DT lifecycle includes (1) Design and requirement definition (R1–R8), (2) Architecture mapping to ISO 23247 entities, (3) Implementation of FEs as ROS 2 packages, (4) Evaluation via a real‑world adaptive cruise control case study, and (5) Deployment in a remote‑management scenario where the DT operates in real time alongside the vehicle."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "The DT asserts real‑time, high‑fidelity reflections: data is collected and processed with network latency <100 ms, clocks are synchronized within 100 ms to preserve event ordering, and ACC logic follows ISO 15622 specifications to ensure safety‑critical correctness; data integrity is maintained through the Data‑Translation FE which normalises units and message types across the system."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "Communication between the vehicle and the cloud uses a Wi‑Fi (802.11ac) link carrying ROS 2 (DDS) messages; the Data Translation Functional Entity handles serialization and unit conversion. Inter‑entity messages within the Digital Twin Entity are also exchanged via ROS 2 topics."
]

instance dt_hosting_deployment : DTDFVocab:Deployment [
    base:desc "The Digital Twin Entity is deployed on cloud‑based infrastructure (e.g., a virtual machine with sufficient GPU/CPU resources) and connects to the vehicle over Wi‑Fi. User interfaces run on client browsers or desktops, leveraging the 3‑D visualization FE, while the physical Twin runs on the NVIDIA Jetson Orin Nano node at the vehicle."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "ISO 23247 (Digital Twin Manufacturing Framework reference architecture) is used to structure the twin; ISO 15622 (ACC standard) defines the control algorithm; ROS 2 is the communication middleware; OPC UA and other standard protocols were considered but not adopted."
]

instance security_and_safety_considerations : DTDFVocab:SecuritySafety [
    base:desc "Safety requirements enforce 100 ms end‑to‑end latency, 100 ms clock synchronization, and ISO 15622 compliance for ACC. Emergency braking can be commanded remotely, highlighting the need for runtime safety. No explicit cybersecurity measures are described in the document."
]
